import { useEffect, useState } from 'react';
import { subscribeDepth } from '../ws/depth';

export function OrderBook({ symbol }: { symbol: string }) {
  const [rows, setRows] = useState<Level[]>([]);
  useEffect(() => subscribeDepth(symbol, (snap) => setRows(snap.levels)), [symbol]);
  return (
    <table>
      <tbody>
        {rows.map((r) => (
          <tr key={r.price}>
            <td>{r.price}</td>
            <td>{r.size}</td>
            <td>{r.total}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

export function subscribeDepth(symbol: string, cb: (snap: Snapshot) => void) {
  const ws = new WebSocket(`wss://md.exchange/depth/${symbol}`);
  ws.onmessage = (e) => cb(JSON.parse(e.data));
  return () => ws.close();
}

import { useSyncExternalStore } from 'react';

type Level = { price: number; size: number; total: number };
let levels: Level[] = [];
let version = 0;
const listeners = new Set<() => void>();
let scheduled = false;

export function applyDelta(snap: { levels: Level[] }) {
  levels = snap.levels; // already sorted by price upstream
  if (!scheduled) {
    scheduled = true;
    requestAnimationFrame(() => {
      scheduled = false;
      version++;
      listeners.forEach((l) => l());
    });
  }
}

export function useDepth() {
  return useSyncExternalStore(
    (cb) => { listeners.add(cb); return () => listeners.delete(cb); },
    () => version
  );
}

export function getLevels() { return levels; }

import { FixedSizeList as List } from 'react-window';
import { useDepth, getLevels } from '../store/depthStore';
import { useEffect } from 'react';
import { subscribeDepth } from '../ws/depth';
import { applyDelta } from '../store/depthStore';

const Row = ({ index, style }: { index: number; style: React.CSSProperties }) => {
  const r = getLevels()[index];
  return (
    <div role="row" style={style}>
      <span role="cell">{r.price}</span>
      <span role="cell">{r.size}</span>
      <span role="cell">{r.total}</span>
    </div>
  );
};

export function OrderBook({ symbol }: { symbol: string }) {
  useDepth();
  useEffect(() => subscribeDepth(symbol, applyDelta), [symbol]);
  return (
    <List height={600} itemCount={getLevels().length} itemSize={24} width={360} overscanCount={8} role="rowgroup">
      {Row}
    </List>
  );
}

export function subscribeDepth(symbol: string, cb: (snap: any) => void) {
  const ws = new WebSocket(`wss://md.exchange/depth/${symbol}`);
  let last = 0;
  ws.onmessage = (e) => {
    const now = performance.now();
    if (now - last < 33) return; // hard cap at 30/s defensive throttle
    last = now;
    cb(JSON.parse(e.data));
  };
  return () => ws.close();
}

