'use client';
import { createContext, useContext, useRef, useSyncExternalStore } from 'react';

type Store = { get: () => string | null; set: (id: string | null) => void; sub: (cb: () => void) => () => void };
const HoverContext = createContext<Store | null>(null);

export function HoverProvider({ children }: { children: React.ReactNode }) {
  const store = useRef<Store>();
  if (!store.current) {
    let val: string | null = null;
    const listeners = new Set<() => void>();
    store.current = {
      get: () => val,
      set: (id) => { val = id; listeners.forEach((l) => l()); },
      sub: (cb) => { listeners.add(cb); return () => listeners.delete(cb); },
    };
  }
  return <HoverContext.Provider value={store.current}>{children}</HoverContext.Provider>;
}

export function useIsHovered(id: string) {
  const store = useContext(HoverContext)!;
  return useSyncExternalStore(store.sub, () => store.get() === id, () => false);
}

export function useSetHover() { return useContext(HoverContext)!.set; }

