import { getPersonalizationBatch } from '../lib/personalization';
import { cookies } from 'next/headers';

export default async function Home() {
  const articles = await getHomepageArticles();
  const session = cookies().get('sid')?.value;
  const meta = await getPersonalizationBatch(session, articles.map((a) => a.id));
  return (
    <div className="grid">
      {articles.map((a) => <ArticleCard key={a.id} article={a} meta={meta.get(a.id)} />)}
    </div>
