export async function getPersonalizationBatch(session: string | undefined, ids: string[]) {
  if (!session) return new Map();
  const res = await fetch(`${process.env.PERS_API}/batch`, {
    method: 'POST',
    headers: { 'content-type': 'application/json', cookie: `sid=${session}` },
    body: JSON.stringify({ ids }),
    next: { revalidate: 0 },
  });
  const arr: { id: string; read: boolean; bookmarked: boolean }[] = await res.json();
  return new Map(arr.map((m) => [m.id, m]));
}

