import L from 'leaflet';
export function reconcileMarkers(
  layer: L.LayerGroup,
  registry: Map<string, L.Marker>,
  list: Vehicle[],
  bounds: L.LatLngBounds,
  onClick: (id: string) => void,
) {
  const seen = new Set<string>();
  for (const v of list) {
    const inView = bounds.pad(0.2).contains([v.lat, v.lng]);
    if (!inView) continue;
    seen.add(v.id);
    const existing = registry.get(v.id);
    if (existing) {
      existing.setLatLng([v.lat, v.lng]);
    } else {
      const m = L.marker([v.lat, v.lng]).addTo(layer);
      m.on('click', () => onClick(v.id));
      registry.set(v.id, m);
    }
  }
  for (const [id, m] of registry) {
    if (!seen.has(id)) { layer.removeLayer(m); registry.delete(id); }
  }
}

import { useState } from 'react';
import { useSelector } from 'react-redux';

export function TransactionsTable() {
  const all = useSelector((s: RootState) => s.txns.list);
  const [q, setQ] = useState('');
  const filtered = all.filter((t) => t.memo.toLowerCase().includes(q.toLowerCase()));
  const sorted = [...filtered].sort((a, b) => b.date - a.date);
  let bal = 0;
  const withBal = sorted.map((t) => ({ ...t, bal: (bal += t.amount) }));
  const totals = filtered.reduce((m, t) => ({ ...m, [t.category]: (m[t.category] || 0) + t.amount }), {} as Record<string, number>);
  return (
    <div>
      <input value={q} onChange={(e) => setQ(e.target.value)} />
      <Totals data={totals} />
      <Rows data={withBal} />
    </div>
  );
}

import { createSelector } from '@reduxjs/toolkit';

const selectList = (s: RootState) => s.txns.list;

export const selectSorted = createSelector([selectList], (list) =>
  [...list].sort((a, b) => b.date - a.date)
);

export const makeSelectView = () =>
  createSelector(
    [selectSorted, (_: RootState, q: string) => q],
    (sorted, q) => {
      const needle = q.toLowerCase();
      const totals: Record<string, number> = {};
      const rows: (Txn & { bal: number })[] = [];
      let bal = 0;
      for (const t of sorted) {
        if (needle && !t.memo.toLowerCase().includes(needle)) continue;
        bal += t.amount;
        rows.push({ ...t, bal });
        totals[t.category] = (totals[t.category] || 0) + t.amount;
      }
      return { rows, totals };
    }
  );

