import { useEffect, useRef, useState } from 'react';

export function Timeline({ events }: { events: Evt[] }) {
  const [active, setActive] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const onScroll = () => {
      const nodes = containerRef.current!.querySelectorAll('[data-section]');
      let current: string | null = null;
      nodes.forEach((n) => {
        const top = (n as HTMLElement).offsetTop - containerRef.current!.scrollTop;
        if (top <= 80) { current = n.getAttribute('data-section'); }
        (n as HTMLElement).classList.toggle('active', top <= 80 && top > -50);
      });
      setActive(current);
    };
    containerRef.current!.addEventListener('scroll', onScroll);
    return () => containerRef.current?.removeEventListener('scroll', onScroll);
  }, []);
  return <div ref={containerRef}>{events.map((e) => <Node key={e.id} evt={e} />)}</div>;
}

import { useEffect, useRef, useState } from 'react';

export function Timeline({ events }: { events: Evt[] }) {
  const [active, setActive] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const activeRef = useRef<string | null>(null);
  useEffect(() => {
    const root = containerRef.current!;
    const obs = new IntersectionObserver((entries) => {
      for (const e of entries) {
        const id = (e.target as HTMLElement).dataset.section!;
        if (e.isIntersecting && activeRef.current !== id) {
          activeRef.current = id;
          setActive(id);
        }
      }
    }, { root, rootMargin: '-10% 0px -85% 0px', threshold: 0 });
    root.querySelectorAll('[data-section]').forEach((n) => obs.observe(n));
    return () => obs.disconnect();
  }, [events.length]);
  return (
    <div ref={containerRef}>
      {events.map((e) => (
        <Node key={e.id} evt={e} active={active === e.section} aria-current={active === e.section ? 'true' : undefined} />
      ))}
    </div>
  );
}

