import { useState } from 'react';
import { parseCsv } from './parseCsv';

export function UploadPanel({ onData }: { onData: (rows: Reading[]) => void }) {
  const [status, setStatus] = useState('idle');
  const handle = async (file: File) => {
    setStatus('parsing');
    const text = await file.text();
    const rows = parseCsv(text); // blocks main thread for ~6s
    onData(rows);
    setStatus('done');
  };
  return <input type="file" onChange={(e) => handle(e.target.files![0])} />;
}

export function parseCsv(text: string): Reading[] {
  const out: Reading[] = [];
  for (const line of text.split('\n')) {
    const [ts, sensor, val] = line.split(',');
    if (!ts) continue;
    const v = Number(val);
    if (v < -50 || v > 150) continue; // range check
    out.push({ ts: Number(ts), sensor, val: v });
  }
  return out;
}

import { validateRow } from './validation';

self.onmessage = async (e: MessageEvent<{ file: File }>) => {
  const { file } = e.data;
  const reader = file.stream().pipeThrough(new TextDecoderStream()).getReader();
  let buf = '';
  const out: Reading[] = [];
  let processed = 0;
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buf += value;
    let nl;
    while ((nl = buf.indexOf('\n')) >= 0) {
      const line = buf.slice(0, nl); buf = buf.slice(nl + 1);
      const row = validateRow(line);
      if (row) out.push(row);
      if (++processed % 50000 === 0) (self as any).postMessage({ type: 'progress', processed });
    }
  }
  (self as any).postMessage({ type: 'done', rows: out });
};

export function validateRow(line: string): Reading | null {
  const i = line.indexOf(',');
  if (i < 0) return null;
  const j = line.indexOf(',', i + 1);
  const ts = Number(line.slice(0, i));
  const sensor = line.slice(i + 1, j);
  const val = Number(line.slice(j + 1));
  if (!ts || val < -50 || val > 150) return null;
  return { ts, sensor, val };
}

import { useState, useRef } from 'react';

export function UploadPanel({ onData }: { onData: (rows: Reading[]) => void }) {
  const [progress, setProgress] = useState(0);
  const [status, setStatus] = useState('idle');
  const workerRef = useRef<Worker | null>(null);
  const handle = (file: File) => {
    setStatus('parsing'); setProgress(0);
    const w = new Worker(new URL('./csv.worker.ts', import.meta.url), { type: 'module' });
    workerRef.current = w;
    w.onmessage = (e) => {
      if (e.data.type === 'progress') setProgress(e.data.processed);
      else { onData(e.data.rows); setStatus('done'); w.terminate(); }
    };
    w.postMessage({ file });
  };
  const cancel = () => { workerRef.current?.terminate(); setStatus('canceled'); };
  return (
    <div>
      <input type="file" onChange={(e) => handle(e.target.files![0])} />
      {status === 'parsing' && <><progress value={progress} max={1200000} /><button onClick={cancel}>Cancel</button></>}
    </div>
  );
}

