import { Directive, HostListener, Input } from '@angular/core';
import { CdkVirtualScrollViewport } from '@angular/cdk/scrolling';

@Directive({ selector: '[logKeyboard]' })
export class LogKeyboardDirective {
  @Input('logKeyboard') vp!: CdkVirtualScrollViewport;
  private idx = 0;
  @HostListener('window:keydown', ['$event'])
  onKey(e: KeyboardEvent) {
    if (e.key === 'j') this.move(1);
    else if (e.key === 'k') this.move(-1);
    else if (e.key === 'G') this.vp.scrollToIndex(this.vp.getDataLength() - 1);
    else if (e.key === 'g') this.vp.scrollToIndex(0);
  }
  private move(d: number) { this.idx = Math.max(0, this.idx + d); this.vp.scrollToIndex(this.idx); }
}

