  setCursor: (id, c) => set((st) => ({ cursors: { ...st.cursors, [id]: c } })),
  undo: () => set((st) => st.past.length ? { shapes: st.past[st.past.length - 1], past: st.past.slice(0, -1), future: [st.shapes, ...st.future] } : st),
  redo: () => set((st) => st.future.length ? { shapes: st.future[0], future: st.future.slice(1), past: [...st.past, st.shapes] } : st),
})));

