import { useRef } from 'react';

export function Column({ cards, onReorder }: { cards: Card[]; onReorder: (order: string[]) => Promise<void> }) {
  const hoverIdx = useRef<number | null>(null);
  const elsRef = useRef<(HTMLDivElement | null)[]>([]);
  const onDragOver = (i: number) => (e: React.DragEvent) => {
    e.preventDefault();
    if (hoverIdx.current === i) return;
    if (hoverIdx.current != null) elsRef.current[hoverIdx.current]?.classList.remove('drop-target');
    elsRef.current[i]?.classList.add('drop-target');
    hoverIdx.current = i;
  };
  const onDrop = (from: number) => () => {
    const to = hoverIdx.current; hoverIdx.current = null;
    if (to == null || to === from) return;
    const order = cards.map((c) => c.id);
    const [moved] = order.splice(from, 1); order.splice(to, 0, moved);
    onReorder(order); // optimistic; parent handles rollback
  };
  const onKey = (i: number) => (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown' && i < cards.length - 1) { const o = cards.map((c) => c.id); [o[i], o[i+1]] = [o[i+1], o[i]]; onReorder(o); }
    if (e.key === 'ArrowUp' && i > 0) { const o = cards.map((c) => c.id); [o[i], o[i-1]] = [o[i-1], o[i]]; onReorder(o); }
  };
  return (
    <div>
      {cards.map((c, i) => (
        <div key={c.id} draggable tabIndex={0} ref={(el) => (elsRef.current[i] = el)}
          onDragOver={onDragOver(i)} onDrop={onDrop(i)} onKeyDown={onKey(i)}>{c.title}</div>
      ))}
    </div>
  );
}

import { useState } from 'react';

export function useOptimisticOrder(initial: Card[], persist: (order: string[]) => Promise<void>) {
  const [cards, setCards] = useState(initial);
  const reorder = async (order: string[]) => {
    const prev = cards;
    setCards(order.map((id) => prev.find((c) => c.id === id)!));
    try { await persist(order); } catch { setCards(prev); /* rollback */ }
  };
  return { cards, reorder };
}

