type Listener = (v: number) => void;
const values = new Map<string, number>();
const listeners = new Map<string, Set<Listener>>();
let pending = new Map<string, number>();
let scheduled = false;

export function pushValue(id: string, v: number) {
  pending.set(id, v);
  if (!scheduled) {
    scheduled = true;
    requestAnimationFrame(() => {
      scheduled = false;
      for (const [id, v] of pending) { values.set(id, v); listeners.get(id)?.forEach((l) => l(v)); }
      pending.clear();
    });
  }
}
export function subscribeGauge(id: string, cb: Listener) {
  if (!listeners.has(id)) listeners.set(id, new Set());
  listeners.get(id)!.add(cb);
  cb(values.get(id) ?? 0);
  return () => listeners.get(id)!.delete(cb);
}

