      {Array.from({ length: 30 }).map((_, i) => <line key={i} x1={50} y1={5} x2={50} y2={10} transform={`rotate(${i * 9} 50 50)`} />)}
      <line ref={needle} x1={50} y1={50} x2={50} y2={12} stroke="black" style={{ transition: 'transform 80ms linear' }} />
    </svg>
  );
}

