import { useEffect, useState, useMemo } from 'react';
import { openMetricsSocket } from './metricsSocket';

export function MetricsDash({ dashboardId, filters }: { dashboardId: string; filters: string[] }) {
  const [data, setData] = useState<Metric[]>([]);
  const filtersKey = useMemo(() => [...filters].sort().join(','), [filters]);
  useEffect(() => {
    const conn = openMetricsSocket(dashboardId, filtersKey, setData);
    return () => conn.close();
  }, [dashboardId, filtersKey]);
  return <Charts data={data} />;
}

export function openMetricsSocket(dashboardId: string, filtersKey: string, onData: (m: Metric[]) => void) {
  let ws: WebSocket | null = null;
  let closed = false;
  let attempt = 0;
  function connect() {
    if (closed) return;
    ws = new WebSocket(`wss://metrics/live?d=${dashboardId}&f=${encodeURIComponent(filtersKey)}`);
    ws.onmessage = (e) => onData(JSON.parse(e.data));
    ws.onclose = () => {
      if (closed) return;
      const delay = Math.min(30000, 500 * 2 ** attempt++);
      setTimeout(connect, delay); // backoff reconnect
    };
    ws.onopen = () => { attempt = 0; };
  }
  connect();
  return { close: () => { closed = true; ws?.close(); } };
}

