import { useState, useEffect } from 'react';

const CHUNK = 50;
export function BlockView({ block }: { block: Block }) {
  const children = block.children ?? [];
  const [count, setCount] = useState(Math.min(CHUNK, children.length));
  useEffect(() => {
    if (count >= children.length) return;
    const h = requestIdleCallback(() => setCount((c) => Math.min(c + CHUNK, children.length)));
    return () => cancelIdleCallback(h);
  }, [count, children.length]);
  return (
    <div className={block.type}>
      {block.props?.text}
      {children.slice(0, count).map((c) => <BlockView key={c.id} block={c} />)}
    </div>
  );
}

