'use client';
import { useState, useEffect } from 'react';
import { formatRemaining } from './formatRemaining';

export function Countdown({ endsAt, serverNow, locale, tz }: { endsAt: string; serverNow: number; locale: string; tz: string }) {
  const [now, setNow] = useState(serverNow); // identical on server and first client render
  useEffect(() => {
    setNow(Date.now());
    const id = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(id);
  }, []);
  const remaining = new Date(endsAt).getTime() - now;
  return <span suppressHydrationWarning>{formatRemaining(remaining, locale, tz)}</span>;
}

export function formatRemaining(ms: number, locale: string, tz: string) {
  const clamped = Math.max(0, ms);
  const totalSec = Math.floor(clamped / 1000);
  const h = String(Math.floor(totalSec / 3600)).padStart(2, '0');
  const m = String(Math.floor((totalSec % 3600) / 60)).padStart(2, '0');
  const s = String(totalSec % 60).padStart(2, '0');
  return `${h}:${m}:${s}`;
}

