import { useEffect, useRef, useState } from 'react';

export function useClusters(stops: Stop[], zoom: number) {
  const z = Math.floor(zoom);
  const [clusters, setClusters] = useState<Cluster[]>([]);
  const worker = useRef<Worker>();
  const lastKey = useRef<string>('');
  useEffect(() => {
    worker.current ??= new Worker(new URL('./cluster.worker.ts', import.meta.url), { type: 'module' });
    worker.current.onmessage = (e) => setClusters(e.data);
    return () => worker.current?.terminate();
  }, []);
  useEffect(() => {
    const key = `${stops.length}:${z}`;
    if (key === lastKey.current) return; // pan at same zoom: skip
    lastKey.current = key;
    worker.current!.postMessage({ stops, zoom: z });
  }, [stops, z]);
  return clusters;
}

import { clusterStops } from './cluster';
self.onmessage = (e: MessageEvent<{ stops: Stop[]; zoom: number }>) => {
  const { stops, zoom } = e.data;
  const clusters = clusterStops(stops, zoom);
  (self as any).postMessage(clusters);
};

