const fmtCache = new Map<string, Intl.DateTimeFormat>();
function fmt(locale: string, zone: string) {
  const key = `${locale}|${zone}`;
  let f = fmtCache.get(key);
  if (!f) {
    f = new Intl.DateTimeFormat(locale, { dateStyle: 'long', timeStyle: 'short', timeZone: zone });
    fmtCache.set(key, f);
  }
  return f;
}
export function formatDate(iso: string, zone: string, locale: string) {
  return fmt(locale, zone).format(new Date(iso));
}
export function groupByDay(rows: Row[]): Record<string, Row[]> {
  return rows.reduce((acc, r) => {
