import { useEffect, useRef, useState } from 'react';

export function LazyImg({ src, alt }: { src: string; alt: string }) {
  const ref = useRef<HTMLImageElement>(null);
  const [load, setLoad] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setLoad(true); }, { rootMargin: '2000px' });
    obs.observe(ref.current!);
    return () => obs.disconnect();
  }, []);
  return <img ref={ref} alt={alt} src={load ? src : undefined} loading="lazy" />;
}

const MAX = 6;
let active = 0;
const queue: (() => void)[] = [];
function pump() { while (active < MAX && queue.length) { active++; queue.shift()!(); } }
export function enqueueLoad(task: (done: () => void) => void) {
  queue.push(() => task(() => { active--; pump(); }));
  pump();
}

import { useEffect, useRef, useState } from 'react';
import { enqueueLoad } from './loadQueue';

export function LazyImg({ src, alt, priority = false }: { src: string; alt: string; priority?: boolean }) {
  const ref = useRef<HTMLImageElement>(null);
  const [resolved, setResolved] = useState<string | undefined>(priority ? src : undefined);
  useEffect(() => {
    if (priority) return;
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) {
        obs.disconnect();
        enqueueLoad((done) => { setResolved(src); const img = ref.current; if (img) { img.onload = done; img.onerror = done; } else done(); });
      }
    }, { rootMargin: '300px', threshold: 0 });
    obs.observe(ref.current!);
    return () => obs.disconnect();
  }, [src, priority]);
  return <img ref={ref} alt={alt} src={resolved} loading={priority ? 'eager' : 'lazy'} fetchPriority={priority ? 'high' : 'auto'} />;
}

