type State = { values: Record<string, string>; errors: Record<string, string> };

export function createFormStore() {
  const state: State = { values: {}, errors: {} };
  const fieldListeners = new Map<string, Set<() => void>>();
  function notify(name: string) { fieldListeners.get(name)?.forEach((l) => l()); }
  function subscribe(name: string, cb: () => void) {
    if (!fieldListeners.has(name)) fieldListeners.set(name, new Set());
    fieldListeners.get(name)!.add(cb);
    return () => fieldListeners.get(name)!.delete(cb);
  }
  function setField(name: string, value: string) {
    state.values[name] = value;
    notify(name);
    if (name === 'startDate' || name === 'endDate') {
      const bad = state.values.endDate && state.values.startDate && state.values.endDate < state.values.startDate;
      state.errors.endDate = bad ? 'End must be after start' : '';
      notify('endDate');
    }
  }
  const getField = (name: string) => ({ value: state.values[name] ?? '', error: state.errors[name] ?? '' });
  const snapshot = () => ({ ...state.values });
  return { subscribe, setField, getField, snapshot };
}

