export function Cell({ value, type, locale }: { value: any; type: string; locale: string }) {
  let text: string;
  if (type === 'currency') text = new Intl.NumberFormat(locale, { style: 'currency', currency: 'USD' }).format(value);
  else if (type === 'percent') text = new Intl.NumberFormat(locale, { style: 'percent' }).format(value);
  else if (type === 'date') text = new Intl.DateTimeFormat(locale).format(new Date(value));
  else text = String(value);
  return <td>{text}</td>;
}

const cache = new Map<string, Intl.NumberFormat | Intl.DateTimeFormat>();
export function getFormatter(type: string, locale: string): (v: any) => string {
  const key = `${type}|${locale}`;
  let f = cache.get(key);
  if (!f) {
    if (type === 'currency') f = new Intl.NumberFormat(locale, { style: 'currency', currency: 'USD' });
    else if (type === 'percent') f = new Intl.NumberFormat(locale, { style: 'percent' });
    else f = new Intl.DateTimeFormat(locale);
    cache.set(key, f);
  }
  const fmt = f;
  return (v: any) => type === 'date' ? (fmt as Intl.DateTimeFormat).format(new Date(v)) : (fmt as Intl.NumberFormat).format(v);
}

