import { getFormatter } from './formatterCache';

export const Cell = memo(function Cell({ value, type, locale }: { value: any; type: string; locale: string }) {
  const text = type === 'plain' ? String(value) : getFormatter(type, locale)(value);
  return <td>{text}</td>;
}, (a, b) => a.value === b.value && a.type === b.type && a.locale === b.locale);

