import { useSyncExternalStore } from 'react';
const selected = new Set<string>();
const listeners = new Map<string, Set<() => void>>();
const totalListeners = new Set<() => void>();
let total = 0;
function notify(id: string) { listeners.get(id)?.forEach((l) => l()); totalListeners.forEach((l) => l()); }
export function toggle(id: string, price: number) {
  if (selected.has(id)) { selected.delete(id); total -= price; } else { selected.add(id); total += price; }
  notify(id);
}
export function useSelected(id: string) {
  return useSyncExternalStore(
    (cb) => { (listeners.get(id) ?? listeners.set(id, new Set()).get(id)!).add(cb); return () => listeners.get(id)!.delete(cb); },
    () => selected.has(id)
  );
}
export function useTotal() {
  return useSyncExternalStore((cb) => { totalListeners.add(cb); return () => totalListeners.delete(cb); }, () => total);
}

